import{_ as d,I as s,o as e,c as n,a7 as a,b as i,w as r,a as l,J as c,a8 as h,ac as g,ad as p,ae as b,af as m,ag as u}from"./chunks/framework.XZRB6_tR.js";const P=JSON.parse('{"title":"音乐管理","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"music.md","filePath":"music.md"}'),_={name:"music.md"};function f(A,t,S,k,x,D){const o=s("Mermaid");return e(),n("div",null,[t[1]||(t[1]=a('<h1 id="音乐管理" tabindex="-1">音乐管理 <a class="header-anchor" href="#音乐管理" aria-label="Permalink to “音乐管理”">​</a></h1><p>相关文档：<a href="/music-free-site/plugin.html">插件</a> · <a href="/music-free-site/plugin-collection.html">插件合集</a> · <a href="/music-free-site/album.html">专辑</a> · <a href="/music-free-site/playlist.html">歌单</a> · <a href="/music-free-site/user.html">用户</a></p><p><img src="'+g+'" alt=""></p><h2 id="_1-模块概述" tabindex="-1">1. 模块概述 <a class="header-anchor" href="#_1-模块概述" aria-label="Permalink to “1. 模块概述”">​</a></h2><p><strong>音乐管理</strong>是 MusicFree 管理后台中的核心运维模块，路径为 <strong><code>/admin/music</code></strong>（侧栏「音乐管理」）。它将三类与曲库质量相关的能力整合在同一页面，通过 Tab 切换：</p><table tabindex="0"><thead><tr><th>Tab</th><th>功能定位</th></tr></thead><tbody><tr><td><strong>音乐搜索</strong></td><td>通过插件从外部平台检索歌曲，并一键下载入库</td></tr><tr><td><strong>音乐去重</strong></td><td>基于音频指纹发现库内重复曲目，支持批量或手动清理</td></tr><tr><td><strong>音乐刮削</strong></td><td>为本地曲目补全/修正元数据（标题、艺术家、专辑、封面、歌词等）</td></tr></tbody></table><p>三者共用同一套 <strong>插件运行时</strong>，但面向的场景不同：搜索/下载侧重「把歌引进来」，去重侧重「库内整洁」，刮削侧重「信息准确」。</p><p>与音乐管理配套的运维能力还包括：</p><ul><li><strong>媒体源</strong>：在 <code>/admin/sources</code> 配置本地媒体源与 WebDAV媒体源，扫描后才有可管理的曲库</li><li><strong>在线播放</strong>：登录用户访问 <code>/music</code> 可浏览曲库并使用 Web 播放器。</li></ul>',9)),(e(),i(h,null,{default:r(()=>[c(o,{id:"mermaid-71",class:"mermaid",graph:"flowchart%20LR%0A%20%20subgraph%20admin%20%5B%E7%AE%A1%E7%90%86%E5%90%8E%E5%8F%B0%20%2Fadmin%2Fmusic%5D%0A%20%20%20%20S%5B%E9%9F%B3%E4%B9%90%E6%90%9C%E7%B4%A2%5D%0A%20%20%20%20D%5B%E9%9F%B3%E4%B9%90%E5%8E%BB%E9%87%8D%5D%0A%20%20%20%20C%5B%E9%9F%B3%E4%B9%90%E5%88%AE%E5%89%8A%5D%0A%20%20end%0A%20%20subgraph%20plugins%20%5BWASM%20%E6%8F%92%E4%BB%B6%5D%0A%20%20%20%20RS%5BRemoteSearch%5D%0A%20%20%20%20RD%5BRemoteDownload%5D%0A%20%20%20%20SS%5BScraperSong%20%2F%20GetCover%20%2F%20GetLyrics%20...%5D%0A%20%20end%0A%20%20subgraph%20library%20%5B%E6%9C%AC%E5%9C%B0%E6%9B%B2%E5%BA%93%5D%0A%20%20%20%20MS%5B%E5%AA%92%E4%BD%93%E6%BA%90%E6%89%AB%E6%8F%8F%5D%0A%20%20%20%20DB%5B(DB)%5D%0A%20%20end%0A%20%20S%20--%3E%20RS%0A%20%20S%20--%3E%20RD%0A%20%20RD%20--%3E%20MS%0A%20%20MS%20--%3E%20DB%0A%20%20C%20--%3E%20SS%0A%20%20SS%20--%3E%20DB%0A%20%20D%20--%3E%20DB%0A"})]),fallback:r(()=>[...t[0]||(t[0]=[l(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<h2 id="_2-访问与权限" tabindex="-1">2. 访问与权限 <a class="header-anchor" href="#_2-访问与权限" aria-label="Permalink to “2. 访问与权限”">​</a></h2><ul><li><strong>音乐管理</strong>：登录管理员账号后，访问 <code>/admin/music</code>即可对所有音乐作品进行管理。</li><li><strong>音乐使用</strong>：登录授权用户访问 <code>/music</code> 浏览曲库并使用播放器。</li></ul><p>相关配置页面：</p><ul><li><strong>插件管理</strong>（<code>/admin/plugin</code>）：安装、启用/禁用插件，编辑插件 JSON 配置。</li><li><strong>媒体源管理</strong>（<code>/admin/sources</code>）：本地/WebDAV 音乐目录、扫描任务。</li></ul><h2 id="_3-音乐搜索-远程搜索与下载" tabindex="-1">3. 音乐搜索（远程搜索与下载） <a class="header-anchor" href="#_3-音乐搜索-远程搜索与下载" aria-label="Permalink to “3. 音乐搜索（远程搜索与下载）”">​</a></h2><p><img src="'+p+'" alt=""></p><h3 id="_3-1-能做什么" tabindex="-1">3.1 能做什么 <a class="header-anchor" href="#_3-1-能做什么" aria-label="Permalink to “3.1 能做什么”">​</a></h3><ul><li>输入<strong>关键词</strong>（歌名、歌手等），在已选中的远程插件上<strong>并行搜索</strong>。</li><li>以<strong>流式</strong>方式展示各插件返回的候选列表（无需等全部插件结束才看到第一条结果）。</li><li>对单条结果点击<strong>下载</strong>：由插件拉取音频 → 写入本地目录 → <strong>自动扫描入库</strong>，即可在 OpenSubsonic 客户端或前端曲库中播放。</li></ul><h3 id="_3-2-界面操作" tabindex="-1">3.2 界面操作 <a class="header-anchor" href="#_3-2-界面操作" aria-label="Permalink to “3.2 界面操作”">​</a></h3><ol><li>在搜索框输入关键词，按 <strong>Enter</strong> 或触发搜索。</li><li>在插件芯片行中勾选要使用的插件（默认全选）；仅显示 manifest 中声明了 <code>remoteSearch</code> 或 <code>remoteDownload</code> 且已启用的插件。</li><li>浏览结果列表：每条展示封面、标题、专辑、艺术家、来源平台、格式、时长等。</li><li>点击 <strong>下载</strong>；成功后提示是否下载成功并入库。</li></ol><h3 id="_3-3-后端行为要点" tabindex="-1">3.3 后端行为要点 <a class="header-anchor" href="#_3-3-后端行为要点" aria-label="Permalink to “3.3 后端行为要点”">​</a></h3><table tabindex="0"><thead><tr><th>环节</th><th>说明</th></tr></thead><tbody><tr><td>并行搜索</td><td>每个插件独立运行的；单插件失败以 <code>plugin_error</code> 事件上报，<strong>不阻断</strong>其他插件</td></tr><tr><td>流式协议</td><td><code>POST /rest/api/v1/remote-search</code> 返回 <strong>NDJSON</strong>（<code>application/x-ndjson</code>），事件类型：<code>start</code> → <code>plugin_result</code> / <code>plugin_error</code> → <code>complete</code></td></tr><tr><td>封面展示</td><td>外链封面经 <code>GET /rest/api/v1/remote-cover?url=...</code> 代理，避免浏览器跨域与鉴权问题</td></tr><tr><td>下载入库</td><td><code>POST /rest/api/v1/remote-download</code>：插件写入 <code>/cache</code> → 宿主搬运到目标目录 → 写标签/嵌入封面 → <strong>单文件即时入库</strong> + 可选触发媒体源扫描</td></tr></tbody></table><h3 id="_3-4-搜索结果字段" tabindex="-1">3.4 搜索结果字段 <a class="header-anchor" href="#_3-4-搜索结果字段" aria-label="Permalink to “3.4 搜索结果字段”">​</a></h3><p>每条远程歌曲记录（<code>RemoteSongRecord</code>）通常包含：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>title</code></td><td>曲名</td></tr><tr><td><code>artist</code></td><td>艺术家</td></tr><tr><td><code>album</code></td><td>专辑（可选）</td></tr><tr><td><code>platform</code></td><td>来源平台（如 netease、qq、kugou）</td></tr><tr><td><code>format</code></td><td>文件格式（mp3、flac 等）</td></tr><tr><td><code>quality</code> / <code>bitrate</code></td><td>音质描述或码率</td></tr><tr><td><code>durationSec</code></td><td>时长（秒）</td></tr><tr><td><code>coverUrl</code></td><td>封面 URL（展示时走代理）</td></tr><tr><td><code>raw</code></td><td>插件私有载荷，下载时原样回传</td></tr></tbody></table><h3 id="_3-5-远程搜索与下载插件" tabindex="-1">3.5 远程搜索与下载插件 <a class="header-anchor" href="#_3-5-远程搜索与下载插件" aria-label="Permalink to “3.5 远程搜索与下载插件”">​</a></h3><p>内置注册表不含远程搜索/下载插件；需在 <a href="/music-free-site/plugin-registry.html">插件注册表</a> 中订阅社区注册表并安装 <code>mf-plugin-gomusicdl</code> 等插件，详见 <a href="/music-free-site/plugin-collection.html">第三方插件合集</a>。</p><h2 id="_4-音乐去重-重复检测" tabindex="-1">4. 音乐去重（重复检测） <a class="header-anchor" href="#_4-音乐去重-重复检测" aria-label="Permalink to “4. 音乐去重（重复检测）”">​</a></h2><p><img src="'+b+'" alt=""></p><h3 id="_4-1-能做什么" tabindex="-1">4.1 能做什么 <a class="header-anchor" href="#_4-1-能做什么" aria-label="Permalink to “4.1 能做什么”">​</a></h3><ul><li>对曲库中已计算 <strong>Chromaprint 指纹</strong> 的歌曲进行两两比对，找出声学上高度相似的重复文件。</li><li>按<strong>重复组</strong>展示结果，支持勾选后<strong>删除</strong>。</li><li>提供 <strong>批量清理重复歌曲</strong>（自动保留一组内的一条）。</li><li>删除默认是软删除，即标记对应的音乐文件为已删除，不会删除音乐源文件中的音乐作品，可在系统配置里面更改为硬删除</li></ul><h3 id="_4-2-使用流程" tabindex="-1">4.2 使用流程 <a class="header-anchor" href="#_4-2-使用流程" aria-label="Permalink to “4.2 使用流程”">​</a></h3><ol><li>点击 <strong>开始检测</strong>，创建异步任务并显示进度（可比对歌曲数、已处理配对、重复组数量等）。</li><li>任务完成后在下方表格按组查看：曲名、艺术家、<strong>匹配分数</strong>、文件路径。</li><li>在组内勾选要移除的条目，点击 <strong>删除</strong>（软删除）；或使用 <strong>批量清理重复歌曲</strong>。</li></ol><blockquote><p><strong>提示</strong>： 仅在同一专辑内去重；跨专辑重复全部保留；同专辑保留优先级为 <code>无损</code> &gt; <code>音质(码率)</code> &gt; <code>时长</code></p></blockquote><h2 id="_5-音乐刮削-元数据补全" tabindex="-1">5. 音乐刮削（元数据补全） <a class="header-anchor" href="#_5-音乐刮削-元数据补全" aria-label="Permalink to “5. 音乐刮削（元数据补全）”">​</a></h2><p><img src="'+m+'" alt=""></p><h3 id="_5-1-能做什么" tabindex="-1">5.1 能做什么 <a class="header-anchor" href="#_5-1-能做什么" aria-label="Permalink to “5.1 能做什么”">​</a></h3><p>本 Tab 嵌入完整的 <strong>元数据刮削</strong> 工作区（<code>ScraperView</code>），用于提升本地曲库信息质量：</p><ul><li><strong>批量刮削</strong>：对未刮削曲目批量补元数据；若在列表中勾选特定歌曲，则对选中项<strong>强制重新刮削</strong>。</li><li><strong>任务面板</strong>：查看当前/历史刮削任务进度与结果。</li><li><strong>插件与策略</strong>：按「艺术家+标题」「艺术家+标题+专辑」等策略，依次尝试已启用的刮削插件（MusicBrainz、网易云、QQ 音乐、Last.fm 等）。</li><li><strong>能力扩展</strong>：支持封面（<code>GetCover</code>）、歌词（<code>GetLyrics</code>）、专辑/艺术家信息（<code>GetAlbumInfo</code> / <code>GetArtistInfo</code>）等，具体取决于各插件 manifest 声明。</li></ul><p>刮削成功后，宿主可将元数据<strong>回写音频文件标签</strong>，并更新音乐数据库。多插件分源策略见 <a href="/music-free-site/plugin-orchestration.html">插件编排</a>。</p><h3 id="_5-2-与「音乐搜索」的区别" tabindex="-1">5.2 与「音乐搜索」的区别 <a class="header-anchor" href="#_5-2-与「音乐搜索」的区别" aria-label="Permalink to “5.2 与「音乐搜索」的区别”">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>音乐搜索</th><th>音乐刮削</th></tr></thead><tbody><tr><td>数据来源</td><td>外部平台 API / 爬虫（插件 <code>RemoteSearch</code>）</td><td>以本地文件已有标签 + 外部元数据库匹配</td></tr><tr><td>主要导出</td><td><code>RemoteSearch</code>、<code>RemoteDownload</code></td><td><code>ScraperSong</code>、<code>GetCover</code>、<code>GetLyrics</code> 等</td></tr><tr><td>典型目标</td><td>下载新歌入库</td><td>修正已有文件的标题/封面/歌词</td></tr><tr><td>是否写文件</td><td>下载新音频并扫描</td><td>常回写 ID3/Vorbis/MP4 标签</td></tr></tbody></table><h2 id="_6-媒体源添加与管理" tabindex="-1">6. 媒体源添加与管理 <a class="header-anchor" href="#_6-媒体源添加与管理" aria-label="Permalink to “6. 媒体源添加与管理”">​</a></h2><p><img src="'+u+`" alt=""> 音乐管理中的搜索、下载、去重、刮削都作用于<strong>已入库</strong>的曲目；曲目必须先通过 <strong>媒体源扫描</strong> 进入数据库。媒体源在管理后台单独页面维护：<strong><code>/admin/sources</code></strong>（侧栏「媒体源管理」），与 <code>/admin/music</code> 配合使用。</p><h3 id="_6-1-媒体源类型" tabindex="-1">6.1 媒体源类型 <a class="header-anchor" href="#_6-1-媒体源类型" aria-label="Permalink to “6.1 媒体源类型”">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>如何配置</th><th>说明</th></tr></thead><tbody><tr><td><strong>本地目录（默认库）</strong></td><td><code>config.yaml</code> → <code>music.library_path</code></td><td>服务端启动时映射为虚拟源 <strong><code>default-library</code></strong>；在列表中展示，<strong>不可</strong>在 Web 上删除或改路径</td></tr><tr><td><strong>WebDAV</strong></td><td><code>/admin/sources</code> → <strong>添加媒体源</strong></td><td>适合 NAS、群晖、Alist 等远程目录；可增删改、测试连接、单独扫描</td></tr></tbody></table><h3 id="_6-2-添加-webdav-媒体源" tabindex="-1">6.2 添加 WebDAV 媒体源 <a class="header-anchor" href="#_6-2-添加-webdav-媒体源" aria-label="Permalink to “6.2 添加 WebDAV 媒体源”">​</a></h3><ol><li>进入 <strong><code>/admin/sources</code></strong>，点击 <strong>添加媒体源</strong>。</li><li>填写： <ul><li><strong>名称</strong>：便于识别的显示名（如「家庭 NAS」）。</li><li><strong>WebDAV URL</strong>：服务根地址，如 <code>https://nas.example.com/webdav</code>。</li><li><strong>用户名 / 密码</strong>：WebDAV 认证（若无需认证可留空，视服务端要求）。</li><li><strong>根路径</strong>：该源下的音乐根目录，如 <code>/music</code> 或 <code>/dav/音频</code>。</li></ul></li><li>勾选 <strong>启用此媒体源</strong>（默认开启）。</li><li>点击 <strong>保存</strong>。</li></ol><p>保存后建议先点卡片上的 <strong>测试连接</strong>（插头图标），确认 URL、账号与路径可访问，再执行扫描。</p><h3 id="_6-3-扫描与维护" tabindex="-1">6.3 扫描与维护 <a class="header-anchor" href="#_6-3-扫描与维护" aria-label="Permalink to “6.3 扫描与维护”">​</a></h3><p>每张媒体源卡片提供：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>测试连接</strong></td><td>校验 WebDAV 可达性</td></tr><tr><td><strong>扫描曲库</strong></td><td>全量扫描该源下音频，解析标签并写入 <code>songs</code> / <code>albums</code> / <code>artists</code></td></tr><tr><td><strong>刷新任务进度</strong></td><td>扫描进行中时显示；列表展示跳过/更新/新增/删除计数</td></tr><tr><td><strong>编辑 / 删除</strong></td><td>仅 <strong>非默认库</strong> 的 WebDAV 源可用</td></tr></tbody></table><p>管理员还可通过 API:</p><ul><li><code>POST /rest/api/v1/sources/:id/scan</code> — 扫描单个源</li><li><code>POST /rest/api/v1/sources/scan-all</code> — 扫描全部已启用源</li><li><code>POST /rest/api/v1/sources/:id/cleanup</code> — 清理库中已不存在的文件记录</li></ul><h2 id="_7-客户端接入与播放" tabindex="-1">7. 客户端接入与播放 <a class="header-anchor" href="#_7-客户端接入与播放" aria-label="Permalink to “7. 客户端接入与播放”">​</a></h2><p>完成媒体源扫描与（可选）音乐管理运维后，除 <strong>Web 前端</strong>（<code>/songs</code>、<code>/albums</code> 等）外，可使用任意兼容 <strong>OpenSubsonic / Subsonic</strong> 的<strong>第三方客户端</strong>浏览同一曲库、流式播放。服务端在 <code>ping</code> 响应中声明 <code>openSubsonic: true</code>、<code>type: MusicFree</code>。</p><h3 id="_7-1-适用场景" tabindex="-1">7.1 适用场景 <a class="header-anchor" href="#_7-1-适用场景" aria-label="Permalink to “7.1 适用场景”">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>说明</th></tr></thead><tbody><tr><td>桌面 / 手机常驻播放器</td><td>Feishin、Symfonium、DSub 类客户端</td></tr><tr><td>车载、TV、音箱</td><td>支持 Subsonic 协议的 App</td></tr><tr><td>与 Web 管理分工</td><td><strong>Web 管理后台</strong>负责搜歌入库、去重、刮削；<strong>客户端</strong>侧重日常听歌</td></tr></tbody></table><p>客户端读取的是扫描入库后的元数据与 <code>stream</code> 地址，<strong>不会</strong>自动执行远程搜索下载或刮削（这些仅在 Web 管理端）。</p><h3 id="_7-2-推荐客户端示例" tabindex="-1">7.2 推荐客户端示例 <a class="header-anchor" href="#_7-2-推荐客户端示例" aria-label="Permalink to “7.2 推荐客户端示例”">​</a></h3><table tabindex="0"><thead><tr><th>客户端</th><th>平台</th><th>备注</th></tr></thead><tbody><tr><td><a href="https://github.com/jeffvli/feishin" target="_blank" rel="noreferrer">Feishin</a></td><td>桌面（Win / macOS / Linux）</td><td>现代 UI，OpenSubsonic 支持较好</td></tr><tr><td>Symfonium</td><td>Android</td><td>功能全面</td></tr><tr><td>DSub / Ultrasonic 等</td><td>Android</td><td>经典 Subsonic 客户端</td></tr><tr><td>各平台 Subsonic 兼容 App</td><td>iOS / 其他</td><td>以是否支持 OpenSubsonic 1.16.x 为准</td></tr></tbody></table><p>具体填法以各客户端「Subsonic 服务器」「OpenSubsonic」设置页为准；服务器类型选 <strong>Subsonic</strong> 或 <strong>OpenSubsonic</strong> 即可。</p><h3 id="_7-3-播放与转码说明" tabindex="-1">7.3 播放与转码说明 <a class="header-anchor" href="#_7-3-播放与转码说明" aria-label="Permalink to “7.3 播放与转码说明”">​</a></h3><ul><li>第三方客户端调用 <code>stream</code> 时，由<strong>客户端</strong>决定是否请求转码（<code>maxBitRate</code>、<code>format</code> 等参数）。</li><li><strong>自动转码</strong>：当客户端请求的格式、码率与源文件不一致时，服务端会转码后以流式响应返回。</li><li>FLAC 等格式能否播放取决于<strong>客户端自身</strong>解码能力，而非音乐管理后台配置。</li></ul><h2 id="_8-典型工作流" tabindex="-1">8. 典型工作流 <a class="header-anchor" href="#_8-典型工作流" aria-label="Permalink to “8. 典型工作流”">​</a></h2><h3 id="_8-1-扩充曲库" tabindex="-1">8.1 扩充曲库 <a class="header-anchor" href="#_8-1-扩充曲库" aria-label="Permalink to “8.1 扩充曲库”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>安装并启用 mf-plugin-gomusicdl</span></span>
<span class="line"><span>    → /admin/music → 音乐搜索</span></span>
<span class="line"><span>    → 输入关键词，选择平台插件</span></span>
<span class="line"><span>    → 流式浏览结果 → 下载</span></span>
<span class="line"><span>    → 自动入库 → 客户端/OpenSubsonic 播放</span></span></code></pre></div><h3 id="_8-2-整理已有库" tabindex="-1">8.2 整理已有库 <a class="header-anchor" href="#_8-2-整理已有库" aria-label="Permalink to “8.2 整理已有库”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>开启 fingerprint → 全库扫描生成指纹</span></span>
<span class="line"><span>    → /admin/music → 音乐去重 → 开始检测</span></span>
<span class="line"><span>    → 审阅重复组 → 软删除多余副本</span></span>
<span class="line"><span>    → 音乐刮削 → 批量刮削补全元数据</span></span></code></pre></div><hr><h3 id="_8-3-配置媒体源并交给客户端播放" tabindex="-1">8.3 配置媒体源并交给客户端播放 <a class="header-anchor" href="#_8-3-配置媒体源并交给客户端播放" aria-label="Permalink to “8.3 配置媒体源并交给客户端播放”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>编辑 config.yaml → music.library_path 指向本地音乐目录</span></span>
<span class="line"><span>    → /admin/sources 添加 WebDAV（可选）→ 测试连接 → 扫描</span></span>
<span class="line"><span>    → /admin/music 搜索下载 / 刮削 / 去重</span></span>
<span class="line"><span>    → Feishin 等填写 http://host:port/rest + 账号</span></span>
<span class="line"><span>    → 客户端浏览播放</span></span></code></pre></div><h2 id="_9-常见问题" tabindex="-1">9. 常见问题 <a class="header-anchor" href="#_9-常见问题" aria-label="Permalink to “9. 常见问题”">​</a></h2><p><strong>Q：搜索页显示「当前无可用远程搜索/下载插件」？</strong><br> A：确认插件已放入 <code>plugins.root</code>、manifest 含 <code>remoteSearch</code>/<code>remoteDownload</code>，且在 <code>/admin/plugin</code> 中已启用。</p><p><strong>Q：Web 上找不到添加本地文件夹的入口？</strong><br> A：本地库路径只在镜像的环境变量中配置，保存后重启服务并扫描虚拟源 <code>default-library</code>；Web 添加媒体源仅用于 <strong>WebDAV</strong>。</p><p><strong>Q：客户端连上但库是空的？</strong><br> A：先确认对应媒体源已 <strong>扫描</strong> 成功；用 Web 端 <code>/songs</code> 验证是否有数据；检查客户端是否选对 <strong>音乐文件夹</strong>（<code>getMusicFolders</code>）。</p><p><strong>Q：客户端能用来搜索下载网易云歌曲吗？</strong><br> A：不能。远程搜索下载仅在 <strong><code>/admin/music</code> → 音乐搜索</strong>（管理员）提供，且需要对应的插件支持；客户端只消费已入库曲库。</p>`,67))])}const y=d(_,[["render",f]]);export{P as __pageData,y as default};
